import os
import shlex
import subprocess
import tempfile
from urllib.parse import unquote

from google.cloud import storage


def image_convert(event, context):
    bucket_name = event["bucket"]
    object_name = unquote(event["name"])
    metadata = event.get("metadata") or {}

    source_filename = metadata.get("filename", object_name)
    convert_options = metadata.get("convert_options", "")

    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(object_name)

    with tempfile.TemporaryDirectory() as tmpdir:
        local_source = os.path.join(tmpdir, os.path.basename(source_filename))
        blob.download_to_filename(local_source)

        base, ext = os.path.splitext(local_source)
        output_ext = metadata.get("output_ext", ".png")
        if not output_ext.startswith("."):
            output_ext = "." + output_ext
        local_output = base + output_ext

        cmd = ["convert", local_source]
        if convert_options:
            cmd.extend(shlex.split(convert_options))
        cmd.append(local_output)

        subprocess.call(cmd)

        output_name = metadata.get("output_name")
        if not output_name:
            output_name = os.path.splitext(object_name)[0] + output_ext

        output_blob = bucket.blob(output_name)
        output_blob.upload_from_filename(local_output)